INSERT INTO new_muslim_path (day_number, audience, title, content_ar, status, is_approved) VALUES
(1, 'all', 'مرحبًا بك في أول أيامك', 'أول ما ننصحك به: خذ نفسًا عميقًا واطمئن. الإسلام دين يُتعلَّم بالتدرج طوال العمر، لا في يوم واحد. أنت الآن نطقت الشهادتين وأصبحت مسلمًا — هذا يكفي للبداية. لا يُشترط أن تعرف كل شيء الآن. في الأيام القادمة سنأخذك خطوة بخطوة: الطهارة، ثم الصلاة، ثم أساسيات العقيدة، ثم آداب الحياة اليومية. اليوم فقط: اطمئن، واعلم أن الله يقبل منك بداية صادقة مهما كانت بسيطة.', 'draft', false),
(2, 'all', 'الطهارة والوضوء', 'الوضوء هو الطهارة التي تسبق الصلاة. خطواته: (1) النية بالقلب، (2) غسل الكفين ثلاثًا، (3) المضمضة والاستنشاق، (4) غسل الوجه ثلاثًا، (5) غسل اليدين إلى المرفقين ثلاثًا، (6) مسح الرأس مرة، (7) مسح الأذنين، (8) غسل القدمين إلى الكعبين ثلاثًا. تدرّب عليه اليوم عمليًا قبل أن تنتقل لتعلّم الصلاة غدًا.', 'draft', false),
(3, 'all', 'الصلاة الأولى', 'لا تنتظر إتقان كل شيء لتصلي أول صلاة. اختر وقتًا هادئًا، توضأ، استقبل القبلة (يمكنك معرفة اتجاهها عبر تطبيقات مواقيت الصلاة)، وابدأ بتكبيرة الإحرام "الله أكبر". اليوم، صلِّ ركعتين بسيطتين ولو بمساعدة نص مكتوب أمامك — الأهم أن تبدأ.', 'draft', false),
(4, 'all', 'سورة الفاتحة', 'الفاتحة ركن في كل ركعة من الصلاة، ولهذا نبدأ بها. احفظها هذا اليوم، وتدرّب على نطقها بتمهّل. معناها الإجمالي: حمد لله، وطلب الهداية إلى الصراط المستقيم.', 'draft', false),
(5, 'all', 'مواقيت الصلاة الخمس', 'الصلوات الخمس: الفجر (قبل شروق الشمس)، الظهر (بعد زوال الشمس عن وسط السماء)، العصر، المغرب (عند غروب الشمس)، العشاء. استخدم تطبيق مواقيت صلاة موثوقًا لمعرفة أوقاتها في مدينتك، وابدأ بالمحافظة على صلاة واحدة أو اثنتين قبل أن تنتقل لباقيها تدريجيًا.', 'draft', false),
(6, 'all', 'أذكار الصباح والمساء الأساسية', 'الذكر يربطك بالله في يومك. ابدأ بذكرين بسيطين: "سبحان الله وبحمده" و"لا إله إلا الله وحده لا شريك له". كررهما في الصباح والمساء، وستجد نفسك تدريجيًا تألف مزيدًا من الأذكار مع الوقت.', 'draft', false),
(7, 'all', 'أسبوعك الأول: توقف وراجع', 'مرّ أسبوع. لا تقارن نفسك بمن حولك من المسلمين منذ الطفولة. راجع ما تعلّمته: الوضوء، الصلاة، الفاتحة. إن فاتتك صلاة أو نسيت خطوة، لا حرج — استأنف. التعلم رحلة لا سباق.', 'draft', false),
(8, 'all', 'أركان الإيمان الستة', 'الإيمان بالله، وملائكته، وكتبه، ورسله، واليوم الآخر، والقدر خيره وشرّه. هذه الأركان أساس عقيدتك — لا يلزمك اليوم أن تتعمّق في تفاصيل كل ركن، فقط تعرّف عليها إجمالًا، وسنُفصّل كل واحد في الأيام القادمة.', 'draft', false),
(9, 'all', 'التوحيد: من هو الله؟', 'التوحيد هو جوهر الإسلام: الإيمان بأن الله واحد لا شريك له، لا في ذاته ولا في صفاته ولا في استحقاقه العبادة. لا وسيط بينك وبين الله في الدعاء والعبادة — تدعوه مباشرة، ويسمعك مباشرة.', 'draft', false),
(10, 'all', 'من هو محمد ﷺ؟', 'محمد ﷺ هو خاتم الأنبياء والمرسلين، بُعث للناس كافة، وليس لقوم بعينهم. نؤمن به رسولًا لا معبودًا، ونتبع هديه لأنه بلّغ عن الله. سنة النبي ﷺ (أقواله وأفعاله) مصدر ثانٍ للتشريع بعد القرآن.', 'draft', false),
(11, 'all', 'القرآن الكريم: كتابك الجديد', 'القرآن كلام الله المُنزَل على محمد ﷺ، محفوظ بلا تحريف منذ نزوله. اقتنِ نسخة (ورقية أو تطبيقًا) بها ترجمة معانٍ إلى لغتك إن لم تكن تجيد العربية بعد، وابدأ بقراءة يسيرة يوميًا، ولو آية أو آيتين بتدبّر.', 'draft', false),
(12, 'all', 'الحلال والحرام: أساسيات فقط', 'لا تنشغل بتفاصيل دقيقة الآن. الأساسيات: اجتناب لحم الخنزير والكحول، والصدق في المعاملات، وحفظ العهد. بقية التفاصيل الفقهية تأتي تدريجيًا — لا تُثقل نفسك بها كلها دفعة واحدة.', 'draft', false),
(13, 'all', 'الصدق والأمانة', 'من أعظم أخلاق المسلم: الصدق في القول، والأمانة في المعاملة، والوفاء بالوعد. هذه القيم ليست إضافية بل جوهر التديّن اليومي — تُمارَس في عملك وبيتك قبل أي شعيرة أخرى.', 'draft', false),
(14, 'all', 'أسبوعان: كيف تشعر؟', 'توقف وتأمل تجربتك حتى الآن. هل هناك سؤال يشغلك؟ شعور بالحيرة طبيعي تمامًا. لا تتردد في التواصل مع داعية عبر المنصة إن احتجت لحديث مباشر عن أي شيء يشغل بالك.', 'draft', false),
(15, 'all', 'الصيام: نظرة عامة', 'صيام رمضان ركن من أركان الإسلام، لكنه ليس واجبًا فوريًا عليك إن لم يحِن رمضان بعد، أو إن كانت ظروفك الصحية تمنعك. اليوم فقط تعرّف على المعنى: الإمساك عن الطعام والشراب من الفجر إلى المغرب تقربًا لله.', 'draft', false),
(16, 'all', 'الزكاة: التكافل المالي', 'الزكاة إخراج نسبة محددة من المال (٢.٥٪ سنويًا من المدّخرات التي بلغت النصاب) للفقراء والمحتاجين. لا تُفرَض عليك فورًا إن لم تملك نصابًا — تعرّف على المبدأ الآن، والتفاصيل حين تحتاجها.', 'draft', false),
(17, 'all', 'الحج: نظرة عامة', 'الحج فريضة على المستطيع مرة في العمر، لا تُطلَب منك فورًا. تعرّف على المعنى الآن: رحلة إلى مكة تجمع المسلمين من كل الأرض في عبادة واحدة موحّدة.', 'draft', false),
(18, 'all', 'التعامل مع الأسرة وغير المسلمين', 'الإسلام يأمر ببرّ الوالدين وصلة الرحم حتى وإن كانوا على غير دينك، ما لم يأمروك بمعصية الله. حافظ على علاقتك بأسرتك بلطف وصبر، وأخبرهم بالتوقيت والطريقة التي تراها مناسبة لظروفك.', 'draft', false),
(19, 'all', 'إيجاد مجتمع مسلم', 'البحث عن مسجد أو مجموعة مسلمين قريبة منك يمنحك دعمًا حقيقيًا: أشخاصًا يجيبون أسئلتك العملية، ومكانًا لتعلّم الصلاة الجماعية إن رغبت. لا عجلة في هذا أيضًا — تحرّك بالسرعة التي تناسبك.', 'draft', false),
(20, 'all', 'الدعاء: حديثك المباشر مع الله', 'الدعاء عبادة مباشرة بلا وسيط ولا صيغة ثابتة إلزامية — يمكنك أن تدعو الله بلغتك الخاصة عمّا يشغل قلبك، في أي وقت. جرّب اليوم أن تدعو بما تشعر به فعلًا.', 'draft', false),
(21, 'all', 'ثلاثة أسابيع: الثبات على الصلوات', 'راجع محافظتك على الصلوات الخمس. إن كنت تصلي بعضها فقط، أضف صلاة واحدة جديدة هذا الأسبوع. التدرّج أفضل من محاولة إتقان كل شيء دفعة ثم التراجع.', 'draft', false),
(22, 'all', 'التوبة والمغفرة', 'كل إنسان يخطئ، والتوبة باب مفتوح دومًا: ندم على الخطأ، وعزم على عدم العودة إليه، وطلب المغفرة من الله مباشرة. لا يحتاج المسلم كاهنًا أو وسيطًا ليتوب.', 'draft', false),
(23, 'all', 'الصبر على التحديات', 'قد تواجه تحديات: أسئلة من محيطك، شعورًا بالوحدة أحيانًا، أو صعوبة في الالتزام. هذا طبيعي تمامًا في أي تحوّل كبير بالحياة. الصبر والاستمرار خطوة بخطوة أهم من الكمال الفوري.', 'draft', false),
(24, 'all', 'آداب الطعام والشراب', 'من الآداب البسيطة: التسمية قبل الأكل ("بسم الله")، والحمد بعده ("الحمد لله")، والأكل باليمين إن أمكن. هذه عادات صغيرة تدخل الإسلام في تفاصيل يومك اليسيرة.', 'draft', false),
(25, 'all', 'الأخلاق مع الناس', 'حسن الخلق جوهر التديّن العملي: كف الأذى، بذل المعروف، طلاقة الوجه، الرفق حتى مع من يخالفك. سلوكك اليومي مع الناس شهادة عملية لدينك أكثر من أي كلام.', 'draft', false),
(26, 'all', 'التعلم المستمر: كيف تواصل؟', 'الآن بعد قرابة شهر، فكّر في خطتك للتعلم المستمر: كتاب مبسّط عن أساسيات الإسلام، درس أسبوعي، أو متابعة داعية موثوق. اختر وسيلة واحدة تناسب وقتك ولا تُثقلك.', 'draft', false),
(27, 'women', 'أحكام خاصة بالمرأة المسلمة الجديدة', 'الحجاب فرض تدريجي التطبيق — لا يلزمك ارتداؤه فورًا في يوم إسلامك، بل يُتعلَّم مع بقية الأحكام بالتدرج والقناعة القلبية أولًا قبل الإلزام الشكلي. تواصلي مع داعية امرأة إن أردت تفصيلًا يراعي ظروفك الخاصة.', 'draft', false),
(28, 'men', 'مسؤوليات إضافية للرجل المسلم الجديد', 'صلاة الجماعة في المسجد مستحبة ومؤكدة للرجال خاصة يوم الجمعة (صلاة الجمعة واجبة على الرجال القادرين). إن استطعت الوصول لمسجد قريب، جرّب حضور صلاة جماعة واحدة هذا الأسبوع دون إلزام نفسك بالكمال الفوري.', 'draft', false),
(29, 'all', 'مراجعة شاملة لشهرك الأول', 'راجع كل ما تعلّمته: الطهارة، الصلاة، أركان الإيمان، أساسيات الأخلاق. اكتب لنفسك ما ترسّخ وما يحتاج مراجعة. لا بأس أن تعود لأي يوم سابق في هذا المسار في أي وقت.', 'draft', false),
(30, 'all', 'يوم الثلاثين: بداية لا نهاية', 'وصلت ليوم الثلاثين، لكن هذا بداية رحلة العمر لا نهايتها. الإسلام يُمارَس ويُتعلَّم مدى الحياة. استمر بخطى ثابتة، ولا تتردد في التواصل مع داعية أو مجتمعك المسلم الجديد كلما احتجت. نسأل الله أن يثبّتك.', 'draft', false)
